`,l.jsx(e.h5,{children:"October 12, 2023 (version 0.1.5)"}),`
`,l.jsxs(e.ul,{children:[`
`,l.jsxs(e.li,{children:["Fixed a bug where adding a bracket on a new line would ",l.jsx("a",{href:"https://github.com/albrow/elara/issues/67",target:"_blank",children:"incorrectly show a missing semicolon error"}),"."]}),`
